### Route Handlers in App Router

Route Handlers replace API Routes in the App Router. Files named `route.js` or `route.ts` export HTTP method handlers:

```jsx
// app/api/items/route.js
export async function GET() {
  const items = await getItems();
  return Response.json(items);
}

export async function POST(request) {
  const item = await request.json();
  const newItem = await createItem(item);
  return Response.json(newItem, { status: 201 });
}
```

### HTTP Methods

Export named functions for each method:

- `GET`
- `POST`
- `PUT`
- `PATCH`
- `DELETE`
- `HEAD`
- `OPTIONS`

### Request and Response

Route Handlers use standard Web APIs:

- `Request` — the standard Fetch API Request object
- `Response` — the standard Fetch API Response object

```jsx
export async function PUT(request, { params }) {
  const body = await request.json();
  const { id } = params;

  const updated = await updateItem(id, body);
  return Response.json(updated);
}

export async function DELETE(request, { params }) {
  const { id } = params;
  await deleteItem(id);
  return new Response(null, { status: 204 });
}
```

### Dynamic Route Handlers

```jsx
// app/api/items/[id]/route.js
export async function GET(request, { params }) {
  const item = await getItem(params.id);

  if (!item) {
    return Response.json({ error: 'Not found' }, { status: 404 });
  }

  return Response.json(item);
}
```

### Revalidating with NextResponse

Use `NextResponse` for advanced features:

```jsx
import { NextResponse } from 'next/server';

export async function GET() {
  const data = await fetchData();

  return NextResponse.json(data, {
    headers: {
      'Cache-Control': 'public, s-maxage=60',
    },
  });
}
```

### CORS and Headers

```jsx
export async function GET() {
  return new Response(JSON.stringify({ message: 'CORS enabled' }), {
    status: 200,
    headers: {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE',
      'Access-Control-Allow-Headers': 'Content-Type',
    },
  });
}

export async function OPTIONS() {
  return new Response(null, {
    status: 204,
    headers: {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE',
      'Access-Control-Allow-Headers': 'Content-Type',
    },
  });
}
```

